// Simulate 30-day timeline by mapping records to dates
const startDate = new Date('2026-01-03');
export const processedData: CallRecord[] = rawData.map((record, index) => {
  const dayOffset = Math.floor(index / 5); // Spread records across 30 days
  const date = new Date(startDate);
  date.setDate(date.getDate() + dayOffset);
  
  return {
    ...record,
    Date: date,
  };
});

// Filter valid records (exclude N/A, voicemails, failed calls)
export const validRecords = processedData.filter(
  (r) => r.Sentiment !== "N/A" && r.Duration > 0 && r.Intent !== "Voicemail"
);

// Utility functions for analytics
export const calculateNHS = (records: CallRecord[]): number => {
  const validSentiments = records.filter(r => r.Sentiment && r.Sentiment !== "N/A");
  if (validSentiments.length === 0) return 0;
  
  const positiveCount = validSentiments.filter(r => r.Sentiment === "Positive").length;
  const improvedShiftCount = records.filter(r => 
    r.Emotional_Shift?.includes("to Pos") || 
    r.Emotional_Shift === "Neut to Pos" || 
    r.Emotional_Shift === "Neg to Pos"
  ).length;
  
  const pctPositive = (positiveCount / validSentiments.length) * 100;
  const pctImproved = (improvedShiftCount / records.length) * 100;
  
  return Math.round(pctPositive + pctImproved);
};

export const getHighChurnCases = (records: CallRecord[]): CallRecord[] => {
  return records.filter(r => r.Churn_Threat === "High");
};

export const getUnhappyCases = (records: CallRecord[]): CallRecord[] => {
  return records.filter(r => 
    r.Sentiment === "Negative" || 
    r.Emotional_Shift?.includes("to Neg") ||
    r.Trust_Confidence_Indicator === "Absent" ||
    r.Churn_Threat === "High"
  );
};

export const getUniqueLocations = (records: CallRecord[]): string[] => {
  const locations = records
    .map(r => r.Clinic_Location)
    .filter(l => l && l !== "N/A" && l !== "Not Specified");
  return [...new Set(locations)];
};

export const getUniqueConcerns = (records: CallRecord[]): string[] => {
  const concerns = records
    .map(r => r.Primary_Concern_Category)
    .filter(c => c && c !== "N/A" && c !== "Not Applicable");
  return [...new Set(concerns)];
};

export const getDoctorStats = (records: CallRecord[]) => {
  const doctorMap = new Map<string, { mentions: number; totalCSAT: number; totalNPS: number; count: number }>();
  
  records.forEach(r => {
    if (r.Doctor_Name && r.Doctor_Name !== "N/A" && r.Doctor_Name.startsWith("Dr.")) {
      const existing = doctorMap.get(r.Doctor_Name) || { mentions: 0, totalCSAT: 0, totalNPS: 0, count: 0 };
      existing.mentions += 1;
      if (r.Doctor_CSAT > 0) {
        existing.totalCSAT += r.Doctor_CSAT;
        existing.count += 1;
      }
      if (r.NPS_Score_10 > 0) {
        existing.totalNPS += r.NPS_Score_10;
      }
      doctorMap.set(r.Doctor_Name, existing);
    }
  });
  
  return Array.from(doctorMap.entries()).map(([name, stats]) => ({
    name,
    mentions: stats.mentions,
    avgCSAT: stats.count > 0 ? stats.totalCSAT / stats.count : 0,
    avgNPS: stats.count > 0 ? stats.totalNPS / stats.count : 0,
  }));
};

export const getTopUnhappyReasons = (records: CallRecord[]) => {
  const reasonMap = new Map<string, number>();
  
  records.forEach(r => {
    if (r.Unhappy_Reason && r.Unhappy_Reason !== "N/A") {
      reasonMap.set(r.Unhappy_Reason, (reasonMap.get(r.Unhappy_Reason) || 0) + 1);
    }
  });
  
  const total = Array.from(reasonMap.values()).reduce((a, b) => a + b, 0);
  
  return Array.from(reasonMap.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([reason, count]) => ({
      reason,
      count,
      percentage: Math.round((count / total) * 100),
    }));
};
